			Hello,
<br/>I want to detect the existence of a microphone and its details before recording.
<br/>I coded the function below. The problem is, I can't get the device name (e.g., cde linux arecord -l result=&quot;card 1: UM1 [WOODBRASS UM1], device 0: USB Audio [USB Audio]&quot;).
<br/>one solution ?
<br/>thanks.
<br/><br/>ma fonction:
<br/><i>//Ctrl existance input MIC
<br/>function MIC_lireinfo(var vMicDeviceName,vMicHostAPIName:string;var vmes:string):boolean;
<br/>var VuosDefaultDeviceIn:cint32;
<br/>&nbsp; &nbsp; VTuos_DeviceInfos:Tuos_DeviceInfos; &nbsp;
<br/>&nbsp; &nbsp; devinf: PPaDeviceInfo;
<br/>&nbsp; &nbsp; apiinf: PPaHostApiInfo;
<br/>begin
<br/>result:=false;vmes:='';
<br/>VuosDefaultDeviceIn:=Pa_GetDefaultInPutDevice ();
<br/>&nbsp; &nbsp; if VuosDefaultDeviceIn=-1
<br/>&nbsp; &nbsp; then vmes:='MIC: pas de micro'
<br/>&nbsp; &nbsp; else begin
<br/>&nbsp; &nbsp; result:=true;
<br/>&nbsp; &nbsp; VTuos_DeviceInfos.DeviceNum :=VuosDefaultDeviceIn;//x;
<br/><br/>&nbsp; &nbsp; devinf := Pa_GetDeviceInfo (VuosDefaultDeviceIn);//x);
<br/>&nbsp; &nbsp; apiinf := Pa_GetHostApiInfo (devinf^.hostApi);
<br/><br/>&nbsp; &nbsp; VTuos_DeviceInfos.DeviceName := UTF8Decode (devinf^._name);
<br/>&nbsp; &nbsp; VTuos_DeviceInfos.HostAPIName := UTF8Decode (apiinf^._name);
<br/><br/>&nbsp; &nbsp; vMicDeviceName:=VTuos_DeviceInfos.DeviceName;
<br/>&nbsp; &nbsp; vMicHostAPIName:=VTuos_DeviceInfos.HostAPIName ;
<br/>&nbsp; &nbsp; end;
<br/>end; &nbsp; </i><br/><br/>Resultat &quot;apiinf^&quot;:
<br/><i>record PAHOSTAPIINFO {
<br/>&nbsp; STRUCTVERSION = 1, 
<br/>&nbsp; _TYPE = PAALSA, 
<br/>&nbsp; _NAME = 'ALSA', 
<br/>&nbsp; DEVICECOUNT = 11, 
<br/>&nbsp; DEFAULTINPUTDEVICE = 10, 
<br/>&nbsp; DEFAULTOUTPUTDEVICE = 10}</i><br/><br/>Resultat &quot;devinf^&quot;:
<br/><i>record PADEVICEINFO {
<br/>&nbsp; STRUCTVERSION = 2, 
<br/>&nbsp; _NAME = 'default', 
<br/>&nbsp; HOSTAPI = 0, 
<br/>&nbsp; MAXINPUTCHANNELS = 32, 
<br/>&nbsp; MAXOUTPUTCHANNELS = 32, 
<br/>&nbsp; DEFAULTLOWINPUTLATENCY = 0.0086848072562358269, 
<br/>&nbsp; DEFAULTLOWOUTPUTLATENCY = 0.0086848072562358269, 
<br/>&nbsp; DEFAULTHIGHINPUTLATENCY = 0.034807256235827665, 
<br/>&nbsp; DEFAULTHIGHOUTPUTLATENCY = 0.034807256235827665, 
<br/>&nbsp; DEFAULTSAMPLERATE = 44100}</i><br/>

			Hi
<br/>I am trying to use 2 usb microphones writting to a file (on windows 11 home 64 bits).
<br/>each of the microphones work one at a time, but when you try to use both it does not work.
<br/><br/>Error is 
<br/><br/>as soon as use 2 usb mics &nbsp; /not enough controller resources. usb
<br/>the record stop &nbsp;seems ok. 
<br/>on application halt
<br/>gives raised exception class 'External: ACCESS VIOLATION' with message Access violation reading from address $FFFFFFFFFFF.
<br/><br/>The directory of the file is
<br/>20/11/2023 &nbsp;11:31 AM &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;46 rec23_11_20_11_31_03.wav
<br/>46 bytes (46 bytes)
<br/>it &nbsp;wont play
<br/><br/>The code is based on the example simple recorder. My appologies if I have not understood the use of uos.
<br/>Using 1 PlayerIndex and uos_AddIntoFile(PlayerIndex1, PChar(FileSaveOutoutName), -1, -1, -1, 4096, outformat);
<br/>code snip (InDev1 =1, InDev2=2, which are devices found by devinfo.) Both work 1 at a time.
<br/><br/>&nbsp; &nbsp;PlayerIndex1 := 0;
<br/>&nbsp; &nbsp; // PlayerIndex : from 0 to what your computer can do ! (depends of ram, cpu, ...)
<br/>&nbsp; &nbsp; // If PlayerIndex exists already, it will be overwritten...
<br/><br/>&nbsp; &nbsp; uos_CreatePlayer(PlayerIndex1);
<br/>&nbsp; &nbsp; //// Create the player.
<br/>&nbsp; &nbsp; //// PlayerIndex : from 0 to what your computer can do !
<br/>&nbsp; &nbsp; //// If PlayerIndex exists already, it will be overwriten...
<br/><br/>&nbsp; &nbsp; //uos_AddIntoFileFromMem(PlayerIndex1, Pchar(edit3.Text));
<br/>&nbsp; &nbsp; //// add Output into wav file (save record) from TMemoryStream &nbsp;with default parameters
<br/>&nbsp; &nbsp; bwav := true; // make it simple
<br/>&nbsp; &nbsp; wantSpeakerOut := False ; // no speaker . make it simple
<br/>&nbsp; &nbsp; if bwav then
<br/>&nbsp; &nbsp; &nbsp;begin
<br/>&nbsp; &nbsp; outformatst := '.wav';
<br/>&nbsp; &nbsp; outformat := 0;
<br/>&nbsp; &nbsp; end else
<br/>&nbsp; &nbsp; begin
<br/>&nbsp; &nbsp; outformatst := '.ogg';
<br/>&nbsp; &nbsp; outformat := 3;
<br/>&nbsp; &nbsp; end;
<br/>&nbsp; &nbsp; FileSaveOutoutName := FileSaveBaseName + 'rec' + &nbsp;UTF8Decode(formatdatetime('YY_MM_DD_HH_mm_ss', now)) + outformatst ;
<br/><br/><br/>&nbsp; &nbsp; &nbsp;// saving in a file using a File-Stream:
<br/><br/>&nbsp; &nbsp; &nbsp;uos_AddIntoFile(PlayerIndex1, PChar(FileSaveOutoutName), -1, -1, -1, 4096, outformat);
<br/><br/>&nbsp;// &nbsp; function uos_AddIntoFile(PlayerIndex: cint32; Filename: PChar; SampleRate: cint32;
<br/>&nbsp;// Channels: cint32; SampleFormat: cint32 ; FramesCount: cint32 ; FileFormat: cint32): cint32;
<br/>// Add a Output into audio wav file with custom parameters from TFileStream
<br/>// PlayerIndex : Index of a existing Player
<br/>// FileName : filename of saved audio wav file
<br/>// SampleRate : delault : -1 (44100)
<br/>// Channels : delault : -1 (2:stereo) (1:mono, 2:stereo, ...)
<br/>// SampleFormat : default : -1 (2:Int16) (1:Int32, 2:Int16)
<br/>// FramesCount : default : -1 (= 65536)
<br/>// FileFormat : default : -1 (wav) (0:wav, 1:pcm, 2:custom, 3:ogg);
<br/><br/>&nbsp; &nbsp; //// add Output into wav or ogg file (save record) from TFileStream
<br/><br/>&nbsp; &nbsp; // saving in a Memory-Buffer:
<br/>&nbsp; &nbsp; // SetLength(thebuffer, 0);
<br/>&nbsp; &nbsp; // uos_AddIntoMemoryBuffer(PlayerIndex1, @thebuffer);
<br/><br/>&nbsp; &nbsp; // saving in a Memory-Stream:
<br/>&nbsp; &nbsp; // if thememorystream = nil then thememorystream := tmemorystream.create;
<br/>&nbsp; &nbsp; // uos_AddIntoMemoryStream(PlayerIndex1, (thememorystream),-1,-1,-1,-1);
<br/><br/>&nbsp; &nbsp; // saving in a file using a Menory-Stream:
<br/>&nbsp; &nbsp; // uos_AddIntoFileFromMem(PlayerIndex1, Pchar(filenameEdit4.filename));
<br/>&nbsp; &nbsp; //// add Output into wav file (save record) &nbsp;with default parameters
<br/><br/>&nbsp; &nbsp; &nbsp; {$if defined(cpuarm) or defined(cpuaarch64)} &nbsp;// need a lower latency
<br/>&nbsp; &nbsp; out1index := uos_AddIntoDevOut(PlayerIndex1, -1, 0.8, -1, -1, -1, -1) ;
<br/>&nbsp; &nbsp; &nbsp; &nbsp;{$else}
<br/>&nbsp; &nbsp; out1index := uos_AddIntoDevOut(PlayerIndex1);
<br/>&nbsp; &nbsp; &nbsp; &nbsp;{$endif}
<br/><br/>&nbsp; &nbsp; uos_outputsetenable(PlayerIndex1, out1index, wantSpeakerOut);
<br/><br/>&nbsp; &nbsp; &nbsp;// uos_AddIntoDevOut(PlayerIndex1, -1, -1, 8000, -1, -1,65536, -1); &nbsp; //// add a Output into device with custom parameters
<br/>&nbsp; &nbsp; //////////// PlayerIndex : Index of a existing Player
<br/>&nbsp; &nbsp; //////////// Device ( -1 is default Output device )
<br/>&nbsp; &nbsp; //////////// Latency &nbsp;( -1 is latency suggested ) )
<br/>&nbsp; &nbsp; //////////// SampleRate : delault : -1 (44100)
<br/>&nbsp; &nbsp; //////////// Channels : delault : -1 (2:stereo) (0: no channels, 1:mono, 2:stereo, ...)
<br/>&nbsp; &nbsp; //////////// SampleFormat : -1 default : Int16 : (0: Float32, 1:Int32, 2:Int16)
<br/>&nbsp; &nbsp; //////////// FramesCount : -1 default : 65536
<br/>&nbsp; &nbsp; // ChunkCount : default : -1 (= 512)
<br/>&nbsp;// these are global variables setup in ini file
<br/>&nbsp;// InDev1: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Integer;
<br/>&nbsp;// InDev2: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Integer;
<br/><br/>&nbsp; &nbsp;useInDevDefault &nbsp;:= true; //default
<br/>&nbsp; &nbsp;useInDev1 := (CheckBoxChan1.Checked) ;
<br/>&nbsp; &nbsp;useInDev2 := (CheckBoxChan2.Checked) ;
<br/>&nbsp; &nbsp;if ( useInDev1) then &nbsp; useInDevDefault := false;
<br/>&nbsp; &nbsp;if ( useInDev2) then &nbsp; useInDevDefault := false;
<br/><br/>&nbsp; &nbsp;// we want useInDevDefault or one or both of &nbsp; useInDev1 &nbsp;useInDev2
<br/>&nbsp; &nbsp;if (useInDevDefault) then
<br/>&nbsp; &nbsp;begin
<br/>&nbsp; &nbsp; &nbsp; &nbsp; In1IndexD := uos_AddFromDevIn(PlayerIndex1); &nbsp; &nbsp; &nbsp; // default
<br/>&nbsp; &nbsp;end;
<br/><br/>&nbsp; &nbsp;if (useInDev1) then
<br/>&nbsp; &nbsp;begin
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;EditCh1.Text := &nbsp;InDev1.ToString;
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;In1Index1 := uos_AddFromDevIn(PlayerIndex1, InDev1,-1,-1,-1,-1,-1,-1);
<br/>&nbsp; &nbsp;end;
<br/>&nbsp; &nbsp; &nbsp;if (useInDev2) then
<br/>&nbsp; &nbsp;begin
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;EditCh2.Text := &nbsp;InDev2.ToString;
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;In1Index2 := uos_AddFromDevIn(PlayerIndex1, InDev2,-1,-1,-1,-1,-1,-1);
<br/>&nbsp; &nbsp;end;
<br/><br/>&nbsp; &nbsp; //// add input from mic with custom parameters
<br/>&nbsp; &nbsp; //////////// PlayerIndex : Index of a existing Player
<br/>&nbsp; &nbsp; //////////// Device ( -1 is default Input device )
<br/>&nbsp; &nbsp; //////////// Latency &nbsp;( -1 is latency suggested ) )
<br/>&nbsp; &nbsp; //////////// SampleRate : delault : -1 (44100)
<br/>&nbsp; &nbsp; //////////// OutputIndex : OutputIndex of existing Output // -1 : all output, -2: no output, other integer : existing output)
<br/>&nbsp; &nbsp; //////////// SampleFormat : -1 default : Int16 : (0: Float32, 1:Int32, 2:Int16)
<br/>&nbsp; &nbsp; //////////// FramesCount : -1 default : 4096 &nbsp; ( &gt; = safer, &lt; = &nbsp;better latency )
<br/><br/>&nbsp; &nbsp; ////////// VolLeft : Left volume
<br/>&nbsp; &nbsp; ////////// VolRight : Right volume
<br/>&nbsp; &nbsp; volLeft &nbsp;:= 1.0;
<br/>&nbsp; &nbsp; volRight := 1.0;
<br/><br/>&nbsp; &nbsp; if (useInDevDefault) then
<br/>&nbsp; &nbsp;begin
<br/>&nbsp; &nbsp; &nbsp; &nbsp; uos_InputAddDSPVolume(PlayerIndex1, In1IndexD, 1, 1);
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;uos_InputSetDSPVolume(PlayerIndex1, &nbsp;In1IndexD, volLeft,volRight, True); /// Set volume
<br/>&nbsp; &nbsp;end;
<br/>&nbsp; &nbsp;if (useInDev1) then
<br/>&nbsp; &nbsp;begin
<br/>&nbsp; &nbsp; &nbsp; &nbsp; uos_InputAddDSPVolume(PlayerIndex1, In1Index1, 1, 1);
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;uos_InputSetDSPVolume(PlayerIndex1, &nbsp;In1Index1, volLeft,volRight, True); /// Set volume
<br/>&nbsp; &nbsp;end;
<br/>&nbsp; &nbsp;if (useInDev2) then
<br/>&nbsp; &nbsp;begin
<br/>&nbsp; &nbsp; &nbsp; &nbsp; uos_InputAddDSPVolume(PlayerIndex1, In1Index2, 1, 1);
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;uos_InputSetDSPVolume(PlayerIndex1, &nbsp;In1Index2, volLeft,volRight, True); /// Set volume
<br/>&nbsp; &nbsp;end;
<br/><br/>&nbsp; &nbsp; ///// DSP Volume changer
<br/>&nbsp; &nbsp; //////////// PlayerIndex : Index of a existing Player
<br/>&nbsp; &nbsp; ////////// In1Index : InputIndex of a existing input
<br/>&nbsp; &nbsp; ////////// VolLeft : Left volume
<br/>&nbsp; &nbsp; ////////// VolRight : Right volume
<br/><br/><br/><br/>&nbsp; &nbsp; uos_Play(PlayerIndex1); &nbsp;/////// everything is ready to play...
<br/>&nbsp; &nbsp; ButtonStart.Enabled:= false ; &nbsp;// wait till stop
<br/>&nbsp; &nbsp; ButtonStop.Enabled:= true ; &nbsp;// allow stop
<br/>end;
<br/><br/>

			Dear all,
<br/><br/>I am trying to use UOS library.
<br/>The objective is to record the sound from my microphone.
<br/>To store the sound in a buffer.
<br/>Then to display the signal in a chart (like an oscilloscope).
<br/>Theres is a problem in the code below.
<br/>The values in the buffer are for example -2.03E27 or 2.33E-37 and a display in a chart does not show wave forms.
<br/>I have exactly the same issue when I store in a buffer a *wav file (which was properly recorded).
<br/>If anyone can help me?
<br/><br/>uos_CreatePlayer(SoundPlayerIndex);
<br/><br/>SampleRate := 44100;
<br/>SampleFormat := 2; // Int16
<br/>Channels := 1; // Mono
<br/>FramesCount := 65536;
<br/><br/>// saving in a Memory-Buffer:
<br/>SetLength(SoundBuffer, 0);
<br/>uos_AddIntoMemoryBuffer(SoundPlayerIndex, @SoundBuffer, SampleRate, SampleFormat, Channels, FramesCount);
<br/><br/>uos_AddFromDevIn(SoundPlayerIndex);
<br/>uos_Play(SoundPlayerIndex);
<br/><br/>sleep(3000); // Duration of recording (I don't know?)
<br/>uos_Stop(SoundPlayerIndex);
<br/>ShowMessage('Recording done');
<br/><br/>// Diplaying in a chart
<br/>ChartSignalLine.Clear;
<br/>for p := Low(SoundBuffer) to High(SoundBuffer) do
<br/>&nbsp; ChartSignalLine.AddXY(p/SampleRate*1e3, SoundBuffer[p]);
<br/><br/>Other question, how can I do that if the recording has 2 channels?
<br/>Many thanks in advance for your reply

			Hello fred.
<br/><br/>I have two usb sound cards connected. 
<br/>I create two players and generate an audio signal for each usb card.
<br/>If I run only one player, everything works fine.
<br/>If I run both players, they interfere with each other. 
<br/>What am I doing wrong?
<br/><br/>Program code:
<br/><br/>//Func for DSP (analog for two player)
<br/>function DSPAfter1,2(var Data: Tuos_Data; var fft: Tuos_FFT): TDArFloat;
<br/>var aArfl: TDArFloat;
<br/>&nbsp; &nbsp; &nbsp;i: integer;
<br/>begin
<br/>&nbsp; setlength(aArfl,Data.OutFrames);
<br/>&nbsp; //generate signal
<br/>&nbsp; for i:=0 to Data.OutFrames-1 do
<br/>&nbsp; aArfl[i]:=0.01*sin(2*pi*1000*i/12000);
<br/>&nbsp; //
<br/>&nbsp; result:=aArfl;
<br/>end;
<br/><br/>//create player
<br/>Function CreatePlayer(aPlayer: integer; aFunc: TFunc)
<br/>begin
<br/>&nbsp; uos_CreatePlayer(aIndex);
<br/>&nbsp; InputIndex:=uos_AddFromEndlessMuted(aPlayer, 2, 480);
<br/>&nbsp; if inputIndex&lt;&gt;-1 then DSPIndex:= uos_InputAddDSP(aPlayer, InputIndex,nil,aFunc, nil,nil);
<br/>&nbsp; if DSPIndex&lt;&gt;-1 then uos_InputeSetDSP(aPlayer, InputIndex. DSPIndex, true);
<br/>&nbsp; OutputIndex:=uos_AddIntoDevOut(aPlayer, -1, -1, 12000, 2, 0, 480, 512);
<br/>&nbsp; if OutputIndex&lt;&gt;-1 then uos_OutputAddDSPVolume(aPlayer, OutputIndex, 1, 1);
<br/>&nbsp;<b>&nbsp;if &quot;not Problems&quot; then uos_play(aPlayer);</b><br/><br/>&nbsp; //Redirecting sound card outputs 
<br/>&nbsp; runcommand('pactl move-sink-input (client index) (usb card out-port index)')
<br/>end;
<br/><br/>//
<br/>Procedure RunPlayers;
<br/>begin
<br/>&nbsp; CreatePlayer(0,DSPAfter1);
<br/>&nbsp; CreatePlayer(1,DSPAfter2);
<br/><br/>&nbsp; //A loop for the console
<br/>&nbsp; while not Terminated do
<br/>&nbsp; begin
<br/>&nbsp; &nbsp; &nbsp;CheckSynchronize(10);
<br/>&nbsp; &nbsp; &nbsp;sleep(5);
<br/>&nbsp; end;
<br/>&nbsp; //
<br/>&nbsp; uos_FreePlayer(0);
<br/>&nbsp; uos_FreePlayer(1);
<br/>end;
<br/>

